// MARK: - StoreKit Delegates

extension HybridWebViewController: SKProductsRequestDelegate, SKPaymentTransactionObserver {

    func productsRequest(_ request: SKProductsRequest, didReceive response: SKProductsResponse) {
        for p in response.products {
            productsById[p.productIdentifier] = p
        }

        let formatter = NumberFormatter()
        formatter.numberStyle = .currency

        let products: [[String: Any]] = response.products.map { p in
            formatter.locale = p.priceLocale
            let priceString = formatter.string(from: p.price) ?? "\(p.price)"
            return [
                "productId": p.productIdentifier,
                "localizedTitle": p.localizedTitle,
                "localizedDescription": p.localizedDescription,
                "price": priceString,
                "priceNumber": p.price,
                "currencyCode": p.priceLocale.currencyCode as Any
            ]
        }

        resolve(callbackId: pendingProductsCallbackId, result: [
            "products": products,
            "invalidProductIds": response.invalidProductIdentifiers
        ])
        pendingProductsCallbackId = nil
        productsRequest = nil
    }

    func request(_ request: SKRequest, didFailWithError error: Error) {
        reject(callbackId: pendingProductsCallbackId, code: "PRODUCTS_REQUEST_FAILED", message: error.localizedDescription, details: nil)
        pendingProductsCallbackId = nil
        productsRequest = nil
    }

    func paymentQueue(_ queue: SKPaymentQueue, updatedTransactions transactions: [SKPaymentTransaction]) {
        for t in transactions {
            switch t.transactionState {
            case .purchased:
                let receipt = appStoreReceiptBase64()
                resolve(callbackId: purchaseCallbackId, result: [
                    "state": "purchased",
                    "productId": t.payment.productIdentifier,
                    "transactionId": t.transactionIdentifier as Any,
                    "originalTransactionId": t.original?.transactionIdentifier as Any,
                    "receiptBase64": receipt as Any
                ])
                queue.finishTransaction(t)
                purchaseCallbackId = nil

            case .failed:
                let nsError = t.error as NSError?
                let isCancelled = (nsError?.code == SKError.paymentCancelled.rawValue)
                reject(callbackId: purchaseCallbackId,
                       code: isCancelled ? "CANCELLED" : "PURCHASE_FAILED",
                       message: nsError?.localizedDescription ?? "Purchase failed",
                       details: ["productId": t.payment.productIdentifier])
                queue.finishTransaction(t)
                purchaseCallbackId = nil

            case .restored:
                let receipt = appStoreReceiptBase64()
                resolve(callbackId: purchaseCallbackId, result: [
                    "state": "restored",
                    "productId": t.payment.productIdentifier,
                    "transactionId": t.transactionIdentifier as Any,
                    "originalTransactionId": t.original?.transactionIdentifier as Any,
                    "receiptBase64": receipt as Any
                ])
                queue.finishTransaction(t)
                purchaseCallbackId = nil

            case .purchasing, .deferred:
                break

            @unknown default:
                break
            }
        }
    }

    private func appStoreReceiptBase64() -> String? {
        guard let url = Bundle.main.appStoreReceiptURL,
              let data = try? Data(contentsOf: url) else { return nil }
        return data.base64EncodedString()
    }
}

// MARK: - AppDelegate / SceneDelegate hooks for Push token forwarding

extension Notification.Name {
    static let HybridDeviceTokenDidUpdate = Notification.Name("HybridDeviceTokenDidUpdate")
    static let HybridDeviceTokenDidFail = Notification.Name("HybridDeviceTokenDidFail")
}

final class HybridPushTokenForwarder {
    static func didRegisterForRemoteNotifications(deviceToken: Data) {
        let token = deviceToken.map { String(format: "%02.2hhx", $0) }.joined()
        NotificationCenter.default.post(name: .HybridDeviceTokenDidUpdate, object: nil, userInfo: ["token": token])
    }

    static func didFailToRegisterForRemoteNotifications(error: Error) {
        NotificationCenter.default.post(name: .HybridDeviceTokenDidFail, object: nil, userInfo: ["error": error.localizedDescription])
    }
}